var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PAWN_REPLACER_NULL_NULL","text":{"KOREA":"크에에에엑!!","JPN":"グエエエエッ！！","ENG":"Aaaack!!","TWN":"唔啊啊啊啊！！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PAWN_REPLACER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PAWN_REPLACER_NULL_NULL","text":{"KOREA":"어, 어째서......! 저놈은......인간인데......! 카운터도 아닌데......","JPN":"な、なぜ……！　あいつは……人間なのに……\\nカウンターでもないのに……","ENG":"H-how come? He’s... just an ordinary human... He’s not even a Counter...","TWN":"為、為什麼……！那傢伙……明明是普通人……！也不是制裁者……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PAWN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PAWN_REPLACER_NULL_NULL","text":{"KOREA":"내가...... 지다니...... 왜.....?!","JPN":"俺が……負けるとは……なぜだ……！？","ENG":"How... did I lose? Why?!","TWN":"我……為什麼……會？！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PAWN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"허억...... 허억......","JPN":"はあ……はあ……","ENG":"*Huff* *Huff*","TWN":"咳咳……咳咳……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이게...... 젠장...... 베테랑이란 거다......","JPN":"これが……クソ……これがベテランの実力だ……","ENG":"This... is what... makes me a damn veteran...","TWN":"這個……該死……的老手……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"바퀴벌레 대왕 같은 놈아...... 아직도 안 뒈졌냐......?","JPN":"このゴキブリ大王め……まだくたばってなかったか……？","ENG":"You big fat stupid roach... You're not dead yet?","TWN":"你這個蟑螂大王……還沒有下地獄嗎……？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PAWN_REPLACER_NULL_NULL","text":{"KOREA":"인정할 수 없다...... 인정할 수 없어! 나는......!!","JPN":"認めない……認められないぞ！　俺は……！！","ENG":"I will not accept this... I cannot accept this! I...","TWN":"我不承認……我不承認！ 我……！！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PAWN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_QM","text":{"KOREA":"실망이군요.","JPN":"がっかりですね。","ENG":"How disappointing.","TWN":"真讓人失望呢。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PAWN_REPLACER_NULL_NULL","text":{"KOREA":"어? 어어?!","JPN":"え？　ええ！？","ENG":"Huh? What?","TWN":"哦？哦哦？！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PAWN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_QM","text":{"KOREA":"정말 안타까워요. 두 번이나 기회를 줬는데도......","JPN":"本当に残念です。二度もチャンスを与えたのに……","ENG":"It’s truly unfortunate. I already gave you two chances...","TWN":"真令人難過呢，都給了你第二次機會……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PAWN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"QUEEN_REPLACER_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_QM","text":{"KOREA":"당신은 나를 계속해서 실망시키는군요.","JPN":"あなたは何度も私をがっかりさせるのですね。","ENG":"But all you did was let me down.","TWN":"你卻一直讓我失望呢。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PAWN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"QUEEN_REPLACER_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PAWN_REPLACER_NULL_NULL","text":{"KOREA":"자, 잠시만요! 아직, 아직 끝나지 않았습니다!","JPN":"ま、待ってください！　まだ、まだ終わりじゃありません！","ENG":"H-hang on! I-I’m not done yet!","TWN":"等一下！我還、還沒有結束！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PAWN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"QUEEN_REPLACER_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PAWN_REPLACER_NULL_NULL","text":{"KOREA":"기회를! 한 번만 더......! 제발!!","JPN":"チャンスを！　もう一度だけ……！　どうか！！","ENG":"Please! Just give me one more chance! I beg you!","TWN":"再給我……再給我一次機會！求求妳！！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PAWN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"QUEEN_REPLACER_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_QM","text":{"KOREA":"유감입니다, 폰.","JPN":"残念です、ポーン。","ENG":"It’s most regrettable, Pawn.","TWN":"我很遺憾，兵卒。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PAWN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"QUEEN_REPLACER_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_QM","text":{"KOREA":"개인적으로는 그러고 싶지만 우리에게도 남은 여유가 그다지 많지 않군요.","JPN":"個人的にはそうしたいところですが、\\n私たちにもあまり余裕がないのです。","ENG":"Personally, I would give you another chance... but we don’t have that luxury right now.","TWN":"雖然我個人很想這樣做，但我們沒有這麼多空閒呢。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PAWN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"QUEEN_REPLACER_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_QM","text":{"KOREA":"귀관의 분전은 결코 잊지 않을 거에요.","JPN":"貴官の奮戦は決して忘れません。","ENG":"I’ll never forget how hard you tried though.","TWN":"我絕不會忘記你的奮戰。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PAWN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"QUEEN_REPLACER_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PAWN_REPLACER_NULL_NULL","text":{"KOREA":"자, 잠깐, 잠깐만!","JPN":"ま、待て、待って！","ENG":"W-wait! Please!","TWN":"等、等一下！請等一下！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PAWN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"QUEEN_REPLACER_NULL_QM","face":"UNIT_IDLE"}}}}]`);export{e as default};